let params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: envie JSON com account_ids (array), date_preset e fields'; }
const token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
const accountIds = params.account_ids || [];
const datePreset = params.date_preset || 'today';
const fields = params.fields || 'spend,impressions,clicks,actions,reach';
if (accountIds.length === 0) return 'Erro: account_ids deve ser um array com pelo menos 1 conta';
try {
  const results = [];
  for (const accountId of accountIds) {
    const url = `https://graph.facebook.com/v19.0/${accountId}/insights?date_preset=${encodeURIComponent(datePreset)}&fields=${encodeURIComponent(fields)}&access_token=${token}`;
    const res = await fetch(url);
    const data = await res.json();
    if (!data.error && data.data && data.data.length > 0) {
      results.push({ account_id: accountId, data: data.data[0] });
    } else if (data.error) {
      results.push({ account_id: accountId, error: data.error.message });
    } else {
      results.push({ account_id: accountId, data: null, note: 'sem dados no período' });
    }
  }
  return JSON.stringify(results);
} catch(e) { return `Erro de conexão: ${e.message}`; }
